For each order, evaluate all existing non-empty assigns and empty slots via cost-delta trials, pick the minimal positive-cost insertion, else fallback to a new assign at end; ensure every order is placed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialResult struct {
		assignIdx int
		costDelta float64
		valid     bool
	}
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		best := trialResult{-1, 1e18, false}
		totalSlots := dispatch.AssignsLen
		if totalSlots < MAXASSIGNS {
			totalSlots = MAXASSIGNS
		}
		for idx := 0; idx < totalSlots; idx++ {
			if idx >= MAXASSIGNS {
				break
			}
			oldCost := float64(0)
			if idx < dispatch.AssignsLen {
				oldCost = dispatch.Assigns[idx].Cost
			}
			if idx >= dispatch.AssignsLen {
				if idx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				} else {
					continue
				}
			}
			savedStateExists := false
			var savedAssign Assign
			if idx < dispatch.AssignsLen {
				savedAssign = dispatch.Assigns[idx]
				savedStateExists = true
			}
			ok := false
			if idx < dispatch.AssignsLen {
				ok = dispatch.Assigns[idx].AddShip(id, oris[shipID], dess[shipID])
			} else {
				if idx < MAXASSIGNS {
					dispatch.Assigns[idx] = Assign{}
					ok = dispatch.Assigns[idx].AddShip(id, oris[shipID], dess[shipID])
				}
			}
			if ok {
				if idx < dispatch.AssignsLen || (idx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS) {
					if idx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
					newCostBeforeGen := dispatch.Assigns[idx].Cost
					_ = newCostBeforeGen
					dispatch.Assigns[idx].GenRoute()
					newCost := dispatch.Assigns[idx].Cost
					if newCost >= 0 {
						delta := newCost - oldCost
						if delta < best.costDelta {
							best.assignIdx = idx
							best.costDelta = delta
							best.valid = true
						}
					}
				}
			}
			if savedStateExists {
				dispatch.Assigns[idx].RemoveShip(id)
				dispatch.Assigns[idx] = savedAssign
				dispatch.Assigns[idx].GenRoute()
			} else {
				if idx >= dispatch.AssignsLen {
					dispatch.Assigns[idx] = Assign{}
				} else {
					dispatch.Assigns[idx].RemoveShip(id)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
		fallbackIdx := -1
		if dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx = dispatch.AssignsLen
		}
		if !best.valid && fallbackIdx != -1 {
			best.assignIdx = fallbackIdx
			best.valid = true
		}
		if best.valid {
			idx := best.assignIdx
			if idx >= dispatch.AssignsLen {
				dispatch.Assigns[idx] = Assign{}
				dispatch.AssignsLen++
			}
			insertOK := dispatch.Assigns[idx].AddShip(id, oris[shipID], dess[shipID])
			if insertOK {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost < 0 {
					dispatch.Assigns[idx].RemoveShip(id)
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen--
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

